onChange.script:
if self.session.custom.terminal.terminalMode != "Dedicated":
	return
if self.session.custom.user.appUserId is None:
	return
if currentValue.value >= 30 and not self.view.custom.modalOpen:
	self.view.custom.modalOpen = True
	system.perspective.openPopup(id="mpp-idle-reconfirm", view="BlueRidge/Components/PlantFloor/IdleReconfirmModal", params={"displayName": self.session.custom.user.displayName, "initials": self.session.custom.user.initials, "popupId": "mpp-idle-reconfirm", "replyMessage": "idleReconfirmResult"}, modal=True, showCloseIcon=False, overlayDismiss=False)
